    slug: string;
    type: string;
    title: string;
    summary: string;
    language: string;
    version: string;
    status: KnowledgeStatus;
    author: string;
    reviewer?: string;
    owner?: string;
    createdAt: string;
    updatedAt: string;
    publishedAt?: string;
    reviewedAt?: string;
    archivedAt?: string;
    canonicalUrl?: string;
    entities: string[];
